module register_with_enable(
	input clk,
	input reset,
	input enable,
	input [15:0] d,
	output reg [15:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
	if (reset)
		q <= 16'b0000000000000000;
	else if (enable)
		q <= d;

endmodule
